// MiPulse VPS API Handler

export async function handleVpsRequest(path, request, env, auth) {
  const db = env.MIPULSE_DB;
  if (!db) return createError('D1 Binding (MIPULSE_DB) not found', 500);

  const parts = path.split('/');
  const method = request.method;

  // Node Report (Public with HMAC)
  if (parts[1] === 'report' && method === 'POST') {
    return handleReport(request, db, env);
  }

  // Dashboard Public View (Token based or open)
  if (parts[1] === 'public' && method === 'GET') {
    return handlePublicList(request, db, env);
  }

  // --- Auth Required Below ---
  if (!auth) return createError('Unauthorized', 401);

  if (parts[1] === 'nodes') {
    if (method === 'GET') {
       if (parts[2]) return handleGetNodeDetail(parts[2], db);
       return handleListNodes(db);
    }
    if (method === 'POST') return handleCreateNode(request, db);
    if (method === 'PUT' && parts[2]) return handleUpdateNode(parts[2], request, db);
    if (method === 'DELETE' && parts[2]) return handleDeleteNode(parts[2], db);
  }

  if (parts[1] === 'alerts') {
    if (method === 'GET') return handleListAlerts(db);
    if (method === 'DELETE') return handleClearAlerts(db);
  }

  return createError('Not Found', 404);
}

// --- Implementation Helpers ---

async function handleReport(request, db, env) {
  const payload = await request.json();
  const { nodeId, timestamp, signature, data } = payload;
  
  const node = await db.prepare('SELECT * FROM vps_nodes WHERE id = ?').bind(nodeId).first();
  if (!node) return createError('Node not found', 404);

  // Signature verification (Simplified HMAC for Demo, should use subtle crypto as in MiSub)
  // For now, let's just use a simple check or implement subtle crypto
  const isValid = await verifyPayloadSignature(node.secret, nodeId, timestamp, data, signature);
  if (!isValid) return createError('Invalid signature', 403);

  // Insert Report
  await db.prepare(`
    INSERT INTO vps_reports (node_id, cpu_percent, mem_percent, disk_percent, load1, uptime_sec, reported_at)
    VALUES (?, ?, ?, ?, ?, ?, ?)
  `).bind(
    nodeId, 
    data.cpu?.usage || data.cpuPercent, 
    data.mem?.usage || data.memPercent, 
    data.disk?.usage || data.diskPercent,
    data.load?.load1 || 0,
    data.uptimeSec || 0,
    new Date(timestamp * 1000).toISOString()
  ).run();

  // Update Node status
  await db.prepare('UPDATE vps_nodes SET last_seen_at = CURRENT_TIMESTAMP, country_code = ? WHERE id = ?')
    .bind(data.meta?.countryCode || '', nodeId).run();

  // Alert check (Simplified)
  if (data.cpu?.usage > 95 || data.mem?.usage > 95) {
     await db.prepare('INSERT INTO vps_alerts (node_id, type, message) VALUES (?, ?, ?)')
      .bind(nodeId, 'overload', `Node ${node.name} is overloaded`).run();
  }

  return createJson({ success: true });
}

async function handleListNodes(db) {
  const { results } = await db.prepare('SELECT * FROM vps_nodes ORDER BY created_at DESC').all();
  // Fetch latest report for each node
  for (const node of results) {
    node.latest = await db.prepare('SELECT * FROM vps_reports WHERE node_id = ? ORDER BY reported_at DESC LIMIT 1')
      .bind(node.id).first();
  }
  return createJson({ success: true, data: results });
}

async function handleCreateNode(request, db) {
  const body = await request.json();
  const id = body.id || crypto.randomUUID();
  const secret = body.secret || Math.random().toString(36).substring(2, 15);
  
  await db.prepare(`
    INSERT INTO vps_nodes (id, name, tag, group_tag, region, description, secret, enabled)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
  `).bind(id, body.name, body.tag, body.groupTag, body.region, body.description, secret, body.enabled ? 1 : 0).run();

  return createJson({ success: true, id, secret });
}

async function handleUpdateNode(id, request, db) {
  const body = await request.json();
  await db.prepare(`
    UPDATE vps_nodes SET name=?, tag=?, group_tag=?, region=?, description=?, enabled=?
    WHERE id = ?
  `).bind(body.name, body.tag, body.groupTag, body.region, body.description, body.enabled ? 1 : 0, id).run();
  return createJson({ success: true });
}

async function handleDeleteNode(id, db) {
  await db.prepare('DELETE FROM vps_nodes WHERE id = ?').bind(id).run();
  return createJson({ success: true });
}

async function handleListAlerts(db) {
  const { results } = await db.prepare('SELECT * FROM vps_alerts ORDER BY created_at DESC LIMIT 100').all();
  return createJson({ success: true, data: results });
}

async function handleClearAlerts(db) {
  await db.prepare('DELETE FROM vps_alerts').run();
  return createJson({ success: true });
}

async function handlePublicList(request, db, env) {
  // Logic same as list nodes but maybe filtered
  const { results } = await db.prepare('SELECT id, name, tag, group_tag, region, last_seen_at FROM vps_nodes WHERE enabled = 1').all();
  for (const node of results) {
    node.latest = await db.prepare('SELECT cpu_percent, mem_percent, disk_percent FROM vps_reports WHERE node_id = ? ORDER BY reported_at DESC LIMIT 1')
      .bind(node.id).first();
  }
  return createJson({ success: true, data: results });
}

// --- Utils ---

function createJson(data) {
  return new Response(JSON.stringify(data), { headers: { 'Content-Type': 'application/json' } });
}

function createError(msg, status = 400) {
  return new Response(JSON.stringify({ error: msg }), { status, headers: { 'Content-Type': 'application/json' } });
}

async function verifyPayloadSignature(secret, nodeId, timestamp, data, signature) {
  const payloadCanonical = JSON.stringify(data);
  const dataToSign = `${nodeId}.${timestamp}.${payloadCanonical}`;
  const key = await crypto.subtle.importKey('raw', new TextEncoder().encode(secret), { name: 'HMAC', hash: 'SHA-256' }, false, ['verify']);
  const isValid = await crypto.subtle.verify('HMAC', key, hexToUint8Array(signature), new TextEncoder().encode(dataToSign));
  return isValid;
}

function hexToUint8Array(hex) {
  const arr = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    arr[i / 2] = parseInt(hex.substr(i, 2), 16);
  }
  return arr;
}
